/* Fix start-screen side drawer geometry after centered layout */
body:not(.pallet-view-active) .side-tab-panel {
  position: fixed !important;
  top: 0 !important;
  bottom: 0 !important;
  left: 0 !important;
  width: min(400px, calc(100vw - 56px)) !important;
  max-width: min(400px, calc(100vw - 56px)) !important;
  height: 100vh !important;
  padding: 30px 24px 24px !important;
  border-radius: 0 24px 24px 0 !important;
  background: linear-gradient(180deg, #0f2138 0%, #102b48 54%, #0a182a 100%) !important;
  overflow: visible !important;
  transform: translateX(-100%) !important;
  z-index: 1000 !important;
  pointer-events: none !important;
}

body:not(.pallet-view-active) .side-tab-panel.drawer-open {
  transform: translateX(0) !important;
  box-shadow: 22px 0 60px rgba(8, 20, 34, 0.32) !important;
  pointer-events: auto !important;
}

body:not(.pallet-view-active) .side-tab-panel:not(.drawer-open) .tab-panel {
  display: none !important;
}

body:not(.pallet-view-active) .side-tab-panel .tabs {
  position: absolute !important;
  top: 50% !important;
  right: -44px !important;
  left: auto !important;
  transform: translateY(-50%) !important;
  display: flex !important;
  flex-direction: column !important;
  gap: 14px !important;
  z-index: 1004 !important;
  pointer-events: auto !important;
}

body:not(.pallet-view-active) .side-tab-panel .tab-panel {
  max-height: calc(100vh - 60px) !important;
  overflow-y: auto !important;
  overflow-x: hidden !important;
  padding: 0 4px 10px 0 !important;
}

body:not(.pallet-view-active) .side-tab-panel .tab-btn {
  pointer-events: auto !important;
}
